import base64, os

b64 = """"""

path = r'D:\Sistema Escolta\escolta_system\cadastros\models.py'
content = base64.b64decode(b64.replace('\n','').replace(' ',''))
open(path, 'wb').write(content)
print(f'Escrito: {len(content)} bytes')
import subprocess
result = subprocess.run(['python', '-c', 
    f"import ast; ast.parse(open(r'{path}', encoding='utf-8').read()); print('SYNTAX OK')"],
    capture_output=True, text=True)
print(result.stdout.strip() or result.stderr.strip())
